INSERT INTO site_content (id, section, data, updated_at) VALUES
('3d8909b4-03c0-4973-9e5c-343e9d01e90a','hero_slides','[{"img":"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=1800&q=90","badge":"Global Distribution Excellence","accent":"Import Solutions","subtitle":"Supplying medical institutions worldwide with precision-sourced medications, surgical supplies, and laboratory equipment."},{"img":"https://images.unsplash.com/photo-1587854692152-cbe660dbde88?w=1800&q=90","badge":"WHO-GMP Certified Sources","accent":"Pharmaceutical Wholesale","subtitle":"Every product meets rigorous international standards including WHO, FDA, and EMA guidelines."},{"img":"https://images.unsplash.com/photo-1579154204601-01588f351e67?w=1800&q=90","badge":"Cold Chain Specialists","accent":"Temperature-Controlled Logistics","subtitle":"IoT-monitored cold chain handling for temperature-sensitive pharmaceuticals."},{"img":"https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?w=1800&q=90","badge":"Surgical & Medical Supplies","accent":"Sterile & Certified","subtitle":"Precision instruments, sterile disposables, and medical consumables for operating theaters worldwide."}]','2026-04-11 16:47:50+03'),
('e297c1a6-3e95-49ae-af9e-1f9b25ec9315','why_choose_us','[{"desc":"Direct sourcing from certified manufacturers only.","icon":"verified","title":"Genuine Products"},{"desc":"Economies of scale passed directly to our clients.","icon":"payments","title":"Competitive Pricing"},{"desc":"Optimized air & sea freight for rapid turnaround.","icon":"local_shipping","title":"Fast Delivery"},{"desc":"Strict adherence to regional health authorities.","icon":"gavel","title":"Licensed & Certified"}]','2026-04-11 16:43:09+03'),
('a481e818-0785-4405-ac2f-edc01f31d2a7','company_info','{"name":"PharmaLink"}','2026-04-11 16:55:50+03'),
('9396f595-fa58-4464-baaa-8ef018486a86','contact_info','[{"icon":"location_on","line1":"Medical Park West, Floor 14","line2":"London, UK EC1A 4HQ","title":"Headquarters"},{"icon":"call","line1":"+44 (0) 20 7946 0123","line2":"Mon–Fri, 9am – 6pm GMT","title":"Phone Support"},{"icon":"mail","line1":"support@pharmalinkwholesale.com","line2":"procurement@pharmalinkwholesale.com","title":"Email"}]','2026-04-11 16:43:09+03'),
('0cb16664-09f5-4bba-acf3-26d2910b1c66','timeline','[{"desc":"PharmaLink established in London as a regional pharmaceutical wholesaler.","year":"2009","title":"Founded"},{"desc":"Achieved WHO-GMP certification, opening doors to international markets.","year":"2012","title":"WHO Certification"},{"desc":"Launched dedicated cold chain division with IoT temperature monitoring.","year":"2015","title":"Cold Chain Launch"},{"desc":"Introduced the first version of our digital RFQ procurement portal.","year":"2018","title":"Digital Platform"},{"desc":"Expanded operations to 50+ countries across 6 continents.","year":"2021","title":"Global Expansion"},{"desc":"Launched PharmaLink Pro — the next generation of B2B pharmaceutical procurement.","year":"2024","title":"PharmaLink Pro"}]','2026-04-11 16:43:09+03'),
('a38d07e8-0c6e-406e-84e6-b2c5af021e08','faq','[{"a":"We respond to all RFQ submissions within 4–24 business hours with a formal quotation.","q":"How quickly do you respond to RFQs?"},{"a":"MOQ varies by product. Many items have no minimum.","q":"What is the minimum order quantity?"},{"a":"Yes. We ship to 50+ countries and handle all customs documentation.","q":"Do you handle international shipping?"},{"a":"All products are sourced exclusively from WHO-GMP certified manufacturers.","q":"Are your products WHO-GMP certified?"}]','2026-04-11 16:43:09+03')
